import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Buenas practicas","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/07-buenas-practicas.md","filePath":"full-stack/arquitectura/ddd/07-buenas-practicas.md","lastUpdated":1782521464000}'),n={name:"full-stack/arquitectura/ddd/07-buenas-practicas.md"};function o(l,e,r,c,p,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h1><p>DDD funciona mejor cuando se aplica con criterio. Usarlo como una lista de patrones puede producir mas complejidad que claridad.</p><h2 id="empieza-por-el-lenguaje" tabindex="-1">Empieza por el lenguaje <a class="header-anchor" href="#empieza-por-el-lenguaje" aria-label="Permalink to &quot;Empieza por el lenguaje&quot;">​</a></h2><p>Antes de crear carpetas, entiende:</p><ul><li>Que problema resuelve el sistema.</li><li>Que palabras usa negocio.</li><li>Que reglas son criticas.</li><li>Que excepciones existen.</li><li>Que decisiones cambian a menudo.</li></ul><h2 id="modela-comportamiento" tabindex="-1">Modela comportamiento <a class="header-anchor" href="#modela-comportamiento" aria-label="Permalink to &quot;Modela comportamiento&quot;">​</a></h2><p>Evita entidades sin comportamiento.</p><p>Mal:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order.status = confirmed</span></span></code></pre></div><p>Mejor:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order.confirm()</span></span></code></pre></div><p>El metodo puede validar invariantes.</p><h2 id="usa-value-objects" tabindex="-1">Usa value objects <a class="header-anchor" href="#usa-value-objects" aria-label="Permalink to &quot;Usa value objects&quot;">​</a></h2><p>Sustituye valores ambiguos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>string email</span></span>
<span class="line"><span>number amount</span></span>
<span class="line"><span>string currency</span></span></code></pre></div><p>Por conceptos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EmailAddress</span></span>
<span class="line"><span>Money</span></span>
<span class="line"><span>Currency</span></span></code></pre></div><h2 id="no-conviertas-ddd-en-ceremonia" tabindex="-1">No conviertas DDD en ceremonia <a class="header-anchor" href="#no-conviertas-ddd-en-ceremonia" aria-label="Permalink to &quot;No conviertas DDD en ceremonia&quot;">​</a></h2><p>No todo necesita:</p><ul><li>Factory.</li><li>Specification.</li><li>Domain service.</li><li>Repository.</li><li>Event.</li></ul><p>Usa patrones cuando resuelvan un problema real.</p><h2 id="protege-limites" tabindex="-1">Protege limites <a class="header-anchor" href="#protege-limites" aria-label="Permalink to &quot;Protege limites&quot;">​</a></h2><p>No dejes que DTOs, ORMs o eventos externos definan tu dominio interno.</p><h2 id="checklist-de-revision" tabindex="-1">Checklist de revision <a class="header-anchor" href="#checklist-de-revision" aria-label="Permalink to &quot;Checklist de revision&quot;">​</a></h2><ul><li>El codigo usa lenguaje del negocio.</li><li>Las reglas viven en el dominio.</li><li>Los agregados son pequenos y consistentes.</li><li>Los contextos tienen limites explicitos.</li><li>Las integraciones no filtran modelos internos.</li><li>Los tests describen reglas de negocio.</li></ul>`,25)])])}const h=a(n,[["render",o]]);export{m as __pageData,h as default};
